# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import requests
import json

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']

    enrich_urls = []
    if 'x-enrich-url' in headers:
        for header_value in headers['x-enrich-url']:
            enrich_urls.append(header_value['value'])

    enriched_data_collection = []
    enriched_header_name = 'X-Enriched-Data'
    HTTP_REQUEST_TIMEOUT_SECONDS = 2

    for url in enrich_urls:
        try:
            response = requests.get(url, timeout=HTTP_REQUEST_TIMEOUT_SECONDS)
            
            if response.status_code == 200:
                enriched_data_collection.append(response.text)
        except requests.exceptions.RequestException:
            pass # Fail gracefully if request fails or times out
        except Exception:
            pass # Catch any other unexpected errors

    if enriched_data_collection:
        try:
            enriched_data_json_string = json.dumps(enriched_data_collection)
            
            headers[enriched_header_name.lower()] = [{
                'key': enriched_header_name,
                'value': enriched_data_json_string
            }]
        except (TypeError, Exception):
            pass # Fail gracefully if JSON serialization or header addition fails

    return request